+// ---------------------------------------------------------------------------
+// Glibc reserved-namespace aliases:
+// __pthread_cond_wait / __pthread_cond_signal / __pthread_cond_broadcast
+// __pthread_kill / __pthread_key_delete
+// ---------------------------------------------------------------------------
